Question: How many consecutive days did the average minutes_awake in additional_sleep across all users decrease, starting from 2022-05-29?
Output requirement: return 1 value(s); types (ordered): {integer}

GeneratedSQL:
WITH daily_avg AS (
    SELECT DATE(start_time) AS date, AVG(minutes_awake) AS avg_minutes_awake
    FROM additional_sleep
    WHERE start_time >= '2022-05-29'
    GROUP BY DATE(start_time)
),
consecutive_days AS (
    SELECT date, avg_minutes_awake,
           @prev_avg := @curr_avg AS prev_avg,
           @curr_avg := avg_minutes_awake,
           @decrease := IF(@curr_avg < @prev_avg, 1, 0) AS is_decrease
    FROM daily_avg, (SELECT @curr_avg := NULL, @prev_avg := NULL) AS vars
    ORDER BY date
)
SELECT COUNT(*) AS consecutive_decrease_days
FROM consecutive_days
WHERE is_decrease = 1
GROUP BY @prev_avg
HAVING COUNT(*) = COUNT(is_decrease);

